  &lt;ol&gt; 
   &lt;li style=&quot;text-align:justify&quot;&gt;&lt;span style=&quot;font-family:Times New Roman,Times,serif;&quot;&gt;&lt;span style=&quot;font-size:10.5pt&quot;&gt;&lt;span style=&quot;vertical-align:top&quot;&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt;&lt;span style=&quot;color:black&quot;&gt;you are&amp;nbsp;a &lt;/span&gt;&lt;/span&gt;&lt;b&gt;&lt;u&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt;&lt;span style=&quot;color:red&quot;&gt;senior student&lt;/span&gt;&lt;/span&gt;&lt;/u&gt;&lt;/b&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt; (enrolled in 2022, 2021, 2020 or earlier) &lt;span style=&quot;color:black&quot;&gt;who is just coming to grab credits rather than study&amp;nbsp;for a Master&#39;s Degree or PHD at Tsinghua or abroad;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt; 
   &lt;li style=&quot;text-align:justify&quot;&gt;&lt;span style=&quot;font-family:Times New Roman,Times,serif;&quot;&gt;&lt;span style=&quot;font-size:10.5pt&quot;&gt;&lt;span style=&quot;vertical-align:top&quot;&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt;you are a &lt;b&gt;&lt;u&gt;&lt;span style=&quot;color:red&quot;&gt;freshman&lt;/span&gt;&lt;/u&gt;&lt;/b&gt; whose &lt;b&gt;&lt;u&gt;&lt;span style=&quot;color:red&quot;&gt;English placement test results&lt;/span&gt;&lt;/u&gt;&lt;/b&gt; belong in &lt;b&gt;&lt;u&gt;&lt;span style=&quot;color:red&quot;&gt;Band 3 and below&lt;/span&gt;&lt;/u&gt;&lt;/b&gt;;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt; 
   &lt;li style=&quot;text-align:justify&quot;&gt;&lt;span style=&quot;font-family:Times New Roman,Times,serif;&quot;&gt;&lt;span style=&quot;font-size:10.5pt&quot;&gt;&lt;span style=&quot;vertical-align:top&quot;&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt;&lt;span style=&quot;color:black&quot;&gt;you are&amp;nbsp;an &lt;/span&gt;&lt;/span&gt;&lt;b&gt;&lt;u&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt;&lt;span style=&quot;color:red&quot;&gt;athlete&lt;/span&gt;&lt;/span&gt;&lt;/u&gt;&lt;/b&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt;&amp;nbsp;or an&amp;nbsp;&lt;b&gt;&lt;u&gt;&lt;span style=&quot;color:red&quot;&gt;art student&lt;/span&gt;&lt;/u&gt;&lt;/b&gt;;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt; 
   &lt;li style=&quot;text-align:justify&quot;&gt;&lt;span style=&quot;font-family:Times New Roman,Times,serif;&quot;&gt;&lt;span style=&quot;font-size:10.5pt&quot;&gt;&lt;span style=&quot;vertical-align:top&quot;&gt;&lt;a rel=&quot;nofollow&quot;&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt;&lt;span style=&quot;color:black&quot;&gt;your &lt;/span&gt;&lt;/span&gt;&lt;/a&gt;&lt;b&gt;&lt;u&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt;&lt;span style=&quot;color:red&quot;&gt;vocabulary size&lt;/span&gt;&lt;/span&gt;&lt;/u&gt;&lt;/b&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt;&lt;span style=&quot;color:black&quot;&gt; is &lt;/span&gt;&lt;/span&gt;&lt;b&gt;&lt;u&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt;&lt;span style=&quot;background:yellow&quot;&gt;&lt;span style=&quot;color:red&quot;&gt;below 8,000&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/u&gt;&lt;/b&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt; (&lt;b&gt;&lt;u&gt;&lt;span style=&quot;color:#00b050&quot;&gt;this is not compulsory&lt;/span&gt;&lt;/u&gt;&lt;/b&gt; but you have to work very much harder, and you have to spend, maybe, two or three hours a day studying the course materials to keep pace with the rest of the class)&lt;span style=&quot;color:black&quot;&gt;;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt; 
   &lt;li style=&quot;text-align:justify&quot;&gt;&lt;span style=&quot;font-family:Times New Roman,Times,serif;&quot;&gt;&lt;span style=&quot;font-size:10.5pt&quot;&gt;&lt;span style=&quot;vertical-align:top&quot;&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt;&lt;span style=&quot;color:black&quot;&gt;your &lt;/span&gt;&lt;/span&gt;&lt;b&gt;&lt;u&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt;&lt;span style=&quot;color:red&quot;&gt;vocabulary size&lt;/span&gt;&lt;/span&gt;&lt;/u&gt;&lt;/b&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt;&lt;span style=&quot;color:black&quot;&gt; is &lt;/span&gt;&lt;/span&gt;&lt;b&gt;&lt;u&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt;&lt;span style=&quot;background:yellow&quot;&gt;&lt;span style=&quot;color:red&quot;&gt;larger than 20,000&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/u&gt;&lt;/b&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt; (because this course will be too easy for you, and you will not learn much as expected)&lt;span style=&quot;color:black&quot;&gt;;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt; 
   &lt;li style=&quot;text-align:justify&quot;&gt;&lt;span style=&quot;font-family:Times New Roman,Times,serif;&quot;&gt;&lt;span style=&quot;font-size:10.5pt&quot;&gt;&lt;span style=&quot;vertical-align:top&quot;&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt;&lt;span style=&quot;color:black&quot;&gt;you have registered for &lt;/span&gt;&lt;/span&gt;&lt;b&gt;&lt;u&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt;&lt;span style=&quot;color:red&quot;&gt;more than 22-credit classes&lt;/span&gt;&lt;/span&gt;&lt;/u&gt;&lt;/b&gt; &lt;b&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt;&lt;span style=&quot;color:#00b050&quot;&gt;(&lt;span style=&quot;background:yellow&quot;&gt;inclusive&lt;/span&gt;)&lt;/span&gt;&lt;/span&gt;&lt;/b&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt;&lt;span style=&quot;color:black&quot;&gt;;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt; 
   &lt;li style=&quot;text-align:justify&quot;&gt;&lt;span style=&quot;font-family:Times New Roman,Times,serif;&quot;&gt;&lt;span style=&quot;font-size:10.5pt&quot;&gt;&lt;span style=&quot;vertical-align:top&quot;&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt;you &lt;b&gt;&lt;u&gt;&lt;span style=&quot;color:red&quot;&gt;cannot&amp;nbsp;afford at least an hour&amp;nbsp;a day on average&lt;/span&gt;&lt;/u&gt; &lt;/b&gt;to&amp;nbsp;study the course materials and do your homework;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt; 
   &lt;li style=&quot;text-align:justify&quot;&gt;&lt;span style=&quot;font-family:Times New Roman,Times,serif;&quot;&gt;&lt;span style=&quot;font-size:10.5pt&quot;&gt;&lt;span style=&quot;vertical-align:top&quot;&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt;you &lt;b&gt;&lt;u&gt;&lt;span style=&quot;color:red&quot;&gt;hold myths&amp;nbsp;and wrong expectations&lt;/span&gt;&lt;/u&gt;&lt;/b&gt; about language teaching and learning;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt; 
   &lt;li style=&quot;text-align:justify&quot;&gt;&lt;span style=&quot;font-family:Times New Roman,Times,serif;&quot;&gt;&lt;span style=&quot;font-size:10.5pt&quot;&gt;&lt;span style=&quot;vertical-align:top&quot;&gt;&lt;a rel=&quot;nofollow&quot;&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt;you often &lt;b&gt;&lt;u&gt;&lt;span style=&quot;color:red&quot;&gt;miss more than two classes&lt;/span&gt;&lt;/u&gt;&lt;/b&gt; &lt;b&gt;&lt;span style=&quot;color:#00b050&quot;&gt;(&lt;span style=&quot;background:yellow&quot;&gt;inclusive&lt;/span&gt;)&lt;/span&gt;&lt;/b&gt; for each course you have registered in the past terms for private reasons and/or without asking for leave; &lt;/span&gt;&lt;/a&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt; 
   &lt;li style=&quot;text-align:justify&quot;&gt;&lt;span style=&quot;font-family:Times New Roman,Times,serif;&quot;&gt;&lt;span style=&quot;font-size:10.5pt&quot;&gt;&lt;span style=&quot;vertical-align:top&quot;&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt;&lt;span style=&quot;color:black&quot;&gt;you registered for this course but never intended to show up&amp;nbsp;for class, and&amp;nbsp;will not drop it&amp;nbsp;until the&amp;nbsp;last&amp;nbsp;minute to&amp;nbsp;do so (&lt;/span&gt;&lt;/span&gt;&lt;b&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt;&lt;span style=&quot;color:red&quot;&gt;personally I do not understand why this is so&lt;/span&gt;&lt;/span&gt;&lt;/b&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt;&lt;span style=&quot;color:black&quot;&gt;); &lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt; 
  &lt;/ol&gt; 
  &lt;p style=&quot;text-align:justify&quot;&gt;&lt;span style=&quot;font-family:Times New Roman,Times,serif;&quot;&gt;&lt;span style=&quot;font-size:10.5pt&quot;&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt;&lt;span style=&quot;color:black&quot;&gt;It is for no other reason than that most of the above-mentioned students will be too busy to put in enough time to study for the course, or will not learn as much as expected, hence I strongly advise that &lt;/span&gt;&lt;/span&gt;&lt;b&gt;&lt;u&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt;&lt;span style=&quot;color:red&quot;&gt;such students drop this class as soon as possible&lt;/span&gt;&lt;/span&gt;&lt;/u&gt;&lt;/b&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt;&lt;span style=&quot;color:black&quot;&gt;!&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt; 
  &lt;p style=&quot;text-align:justify&quot;&gt;&amp;nbsp;&lt;/p&gt; 
  &lt;p style=&quot;text-align:justify&quot;&gt;&lt;span style=&quot;font-family:Times New Roman,Times,serif;&quot;&gt;&lt;span style=&quot;font-size:10.5pt&quot;&gt;&lt;span style=&quot;font-size:12.0pt&quot;&gt;&lt;span style=&quot;color:black&quot;&gt;Thank you for your understanding and cooperation! &lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;text-align:center; text-indent:21.0pt&quot;&gt;&lt;span style=&quot;font-size:10.5pt&quot;&gt;&lt;span style=&quot;background:white&quot;&gt;&lt;span style=&quot;font-family:Calibri,sans-serif&quot;&gt;&lt;strong&gt;&lt;span style=&quot;border:none windowtext 1.0pt; font-size:22.0pt; padding:0cm&quot;&gt;&lt;span style=&quot;font-family:&amp;quot;Monotype Corsiva&amp;quot;&quot;&gt;&lt;span style=&quot;color:#444444&quot;&gt;&lt;span style=&quot;background-color:#27ae60;&quot;&gt;Criminal Minds&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;b&gt;&lt;span style=&quot;border:none windowtext 1.0pt; font-size:22.0pt; padding:0cm&quot;&gt;&lt;span style=&quot;font-family:&amp;quot;Monotype Corsiva&amp;quot;&quot;&gt;&lt;span style=&quot;color:#444444&quot;&gt; &lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/b&gt;&lt;b&gt;&lt;span style=&quot;border:none windowtext 1.0pt; font-size:22.0pt; padding:0cm&quot;&gt;&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;&lt;span style=&quot;color:#444444&quot;&gt;&amp;amp;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/b&gt;&lt;b&gt;&lt;span style=&quot;border:none windowtext 1.0pt; font-size:22.0pt; padding:0cm&quot;&gt;&lt;span style=&quot;font-family:&amp;quot;Monotype Corsiva&amp;quot;&quot;&gt;&lt;span style=&quot;color:#444444&quot;&gt; &lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/b&gt;&lt;span style=&quot;color:#27ae60;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;border:none windowtext 1.0pt; font-size:22.0pt; padding:0cm&quot;&gt;&lt;span style=&quot;font-family:&amp;quot;Monotype Corsiva&amp;quot;&quot;&gt;Mind hunters&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt; 
  &lt;p style=&quot;text-align:justify; margin-top:5px; margin-bottom:5px&quot;&gt;&lt;span style=&quot;font-size:12pt&quot;&gt;&lt;span style=&quot;text-justify:inter-ideograph&quot;&gt;&lt;span style=&quot;font-family:宋体&quot;&gt;&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;From what I understand about language learning, or language acquisition, watching videos is the best way to help learners improve their language proficiency, and&amp;nbsp;&lt;b&gt;&lt;i&gt;Criminal Minds&lt;/i&gt;&lt;/b&gt;&amp;nbsp;is such American TV drama series&amp;nbsp;(which is composed of 324 episodes out of 15 seasons),&amp;nbsp;and is, personally, the best, ever.&amp;nbsp; Here are the links to &quot;&lt;b&gt;&lt;i&gt;Criminal Minds&lt;/i&gt;&lt;/b&gt;&quot; &amp;amp; &quot;&lt;b&gt;&lt;i&gt;Mind hunters&lt;/i&gt;&lt;/b&gt;&quot; (which is about the establishment of the predecessor of BAU those resourceful FBI agents work for.)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt; 
  &lt;p style=&quot;text-align:justify; margin-top:5px; margin-bottom:5px&quot;&gt;&lt;span style=&quot;font-size:12pt&quot;&gt;&lt;span style=&quot;text-justify:inter-ideograph&quot;&gt;&lt;span style=&quot;font-family:宋体&quot;&gt;&lt;i&gt;&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;&lt;span style=&quot;background-color:#27ae60;&quot;&gt;Criminal Minds&lt;/span&gt;&lt;/span&gt;&lt;/i&gt;&lt;b&gt;&lt;i&gt;&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt; &lt;/span&gt;&lt;/i&gt;&lt;/b&gt;&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;&amp;nbsp;(S01 - S015) (324 episodes)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt; 
  &lt;p style=&quot;margin-left:84px; text-align:justify; text-indent:21.0pt; margin-top:5px; margin-bottom:5px&quot;&gt;&lt;span style=&quot;font-size:12pt&quot;&gt;&lt;span style=&quot;text-justify:inter-ideograph&quot;&gt;&lt;span style=&quot;font-family:宋体&quot;&gt;清华云盘链接：&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;https://cloud.tsinghua.edu.cn/d/93ce0e5f329742dcad67/&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt; 
  &lt;p style=&quot;text-align:justify; margin-top:5px; margin-bottom:5px&quot;&gt;&lt;span style=&quot;font-size:12pt&quot;&gt;&lt;span style=&quot;text-justify:inter-ideograph&quot;&gt;&lt;span style=&quot;font-family:宋体&quot;&gt;【特别提示】从&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;S01E01&lt;/span&gt;到&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;S15E10&lt;/span&gt;，本人开设的四门课程里的各种级别的词汇被反反复复用到，所以从语言习得的角度，个人以为&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;Criminal Minds&lt;/span&gt;绝对是最好的美剧！请同学们一定要花时间去看哈！加油！！！&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt; 
  &lt;p style=&quot;text-align:justify; margin-top:5px; margin-bottom:5px&quot;&gt;&lt;span style=&quot;font-size:12pt&quot;&gt;&lt;span style=&quot;text-justify:inter-ideograph&quot;&gt;&lt;span style=&quot;font-family:宋体&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt; 
  &lt;p style=&quot;text-align:justify; margin-top:5px; margin-bottom:5px&quot;&gt;&lt;span style=&quot;font-size:12pt&quot;&gt;&lt;span style=&quot;text-justify:inter-ideograph&quot;&gt;&lt;span style=&quot;font-family:宋体&quot;&gt;&lt;strong&gt;&lt;i&gt;&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;&lt;span style=&quot;background-color:#27ae60;&quot;&gt;Mind Hunters&lt;/span&gt;&lt;/span&gt;&lt;/i&gt;&lt;/strong&gt;&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt; (S01 - S02) (19 episodes) &lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt; 
  &lt;p style=&quot;margin-left:84px; text-align:justify; text-indent:21.0pt; margin-top:5px; margin-bottom:5px&quot;&gt;&lt;span style=&quot;font-size:12pt&quot;&gt;&lt;span style=&quot;text-justify:inter-ideograph&quot;&gt;&lt;span style=&quot;font-family:宋体&quot;&gt;清华云盘链接：&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;(&lt;span style=&quot;background:red&quot;&gt;to be continued&lt;/span&gt;)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt; 
  &lt;p style=&quot;text-align:justify; margin-top:5px; margin-bottom:5px&quot;&gt;&lt;span style=&quot;font-size:12pt&quot;&gt;&lt;span style=&quot;text-justify:inter-ideograph&quot;&gt;&lt;span style=&quot;font-family:宋体&quot;&gt;【特别提示】&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;Mind Hunters &lt;/span&gt;讲的是&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;Criminal Minds&lt;/span&gt;里的&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;FBI&lt;/span&gt;探员隶属的工作单位&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;BAU&lt;/span&gt;的前身&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;BSU&lt;/span&gt;（好像是叫这个）。&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;S01&lt;/span&gt;尤其超级棒！&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;text-align:justify; margin-top:5px; margin-bottom:5px&quot;&gt;&lt;span style=&quot;font-size:12pt&quot;&gt;&lt;span style=&quot;text-justify:inter-ideograph&quot;&gt;&lt;span style=&quot;font-family:宋体&quot;&gt;&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;Hi, guys! &lt;/span&gt;&lt;b&gt;&lt;span style=&quot;font-size:14.0pt&quot;&gt;&lt;span style=&quot;background:yellow&quot;&gt;&lt;span style=&quot;font-family:&amp;quot;Monotype Corsiva&amp;quot;&quot;&gt;&lt;span style=&quot;color:red&quot;&gt;Happy New Year!&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/b&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt; 
  &lt;p style=&quot;text-align:justify; margin-top:5px; margin-bottom:5px&quot;&gt;&lt;span style=&quot;font-size:12pt&quot;&gt;&lt;span style=&quot;text-justify:inter-ideograph&quot;&gt;&lt;span style=&quot;font-family:宋体&quot;&gt;&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;I am WANG Ying, instructor of the English&amp;nbsp;course&amp;nbsp;&ndash; &lt;em&gt;&lt;b&gt;Word Power Made Easy&lt;/b&gt;&lt;/em&gt;&amp;nbsp;for the upcoming spring term of the school year 2025 - 2026. At the beginning of each semester, I am so eager to meet&amp;nbsp;all of you that&amp;nbsp;I cannot wait to see you in class because I &quot;enjoy so much torturing you&quot;&amp;nbsp;as some former students of mine&amp;nbsp;referred to it. With due&amp;nbsp;reflection of previous semesters&#39;&amp;nbsp;teaching, students&#39; feedback and careful preparations, I think I can do a better job than before this semester.&amp;nbsp;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt; 
  &lt;p style=&quot;text-align:justify; margin-top:5px; margin-bottom:5px&quot;&gt;&lt;span style=&quot;font-size:12pt&quot;&gt;&lt;span style=&quot;text-justify:inter-ideograph&quot;&gt;&lt;span style=&quot;font-family:宋体&quot;&gt;&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;But are you ready?&amp;nbsp;If you have ever heard anything about my classes, you should have known it: No freeloaders, never, ever, could make it to the end of the semester. Hopefully, you are not one of those guys. But if you are, please drop this course immediately&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;font-size:10.5pt&quot;&gt;&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;if possible&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;font-size:12pt&quot;&gt;&lt;span style=&quot;text-justify:inter-ideograph&quot;&gt;&lt;span style=&quot;font-family:宋体&quot;&gt;&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt; to make room for other students who want to study the course wholeheartedly.&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt; 
  &lt;p style=&quot;text-align:justify; margin-top:5px; margin-bottom:5px&quot;&gt;&lt;span style=&quot;font-size:12pt&quot;&gt;&lt;span style=&quot;text-justify:inter-ideograph&quot;&gt;&lt;span style=&quot;font-family:宋体&quot;&gt;&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;By the way,&amp;nbsp;could you please bring to class&amp;nbsp;some scratch paper, or note paper, and a colored pen, or a highlighter, if you will, when you show up for class the first week? And, of course, bring yourself, too!&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt; 
  &lt;p style=&quot;text-align:justify; margin-top:5px; margin-bottom:5px&quot;&gt;&lt;span style=&quot;font-size:12pt&quot;&gt;&lt;span style=&quot;text-justify:inter-ideograph&quot;&gt;&lt;span style=&quot;font-family:宋体&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt; 
  &lt;p style=&quot;text-align:justify; margin-top:5px; margin-bottom:5px&quot;&gt;&lt;span style=&quot;font-size:12pt&quot;&gt;&lt;span style=&quot;text-justify:inter-ideograph&quot;&gt;&lt;span style=&quot;font-family:宋体&quot;&gt;&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;See you guys soon!&amp;nbsp;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt; 
  &lt;p style=&quot;text-align:justify; margin-top:5px; margin-bottom:5px&quot;&gt;&lt;span style=&quot;font-size:12pt&quot;&gt;&lt;span style=&quot;text-justify:inter-ideograph&quot;&gt;&lt;span style=&quot;font-family:宋体&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt; 
  &lt;p style=&quot;margin-left:57px; text-align:justify; text-indent:-42.5pt; margin-top:5px; margin-bottom:5px&quot;&gt;&lt;span style=&quot;font-size:12pt&quot;&gt;&lt;span style=&quot;text-justify:inter-ideograph&quot;&gt;&lt;span style=&quot;font-family:宋体&quot;&gt;【&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;P.S.&lt;/span&gt;】&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;Please make sure you have secured a copy of the textbooks to be used in class (e-copies of which will be available in the course files under correspondent titles) (also see &lt;span style=&quot;background:yellow&quot;&gt;&lt;span style=&quot;color:red&quot;&gt;Announcement #2&lt;/span&gt;&lt;/span&gt; for detail):&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt; 
  &lt;ol style=&quot;margin-top:5px; margin-bottom:5px&quot;&gt; 
   &lt;li style=&quot;margin-left:36px; text-align:justify; margin-top:5px; margin-bottom:5px&quot;&gt;&lt;span style=&quot;font-size:12pt&quot;&gt;&lt;span style=&quot;text-justify:inter-ideograph&quot;&gt;&lt;span style=&quot;font-family:宋体&quot;&gt;&lt;strong&gt;&lt;i&gt;&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;&lt;span style=&quot;background-color:#27ae60;&quot;&gt;Word Power Made Easy&lt;/span&gt;&lt;/span&gt;&lt;/i&gt;&lt;/strong&gt;&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt; (&lt;i&gt;by Norman Lewis&lt;/i&gt;);&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt; 
   &lt;li style=&quot;margin-left:36px; text-align:justify; margin-top:5px; margin-bottom:5px&quot;&gt;&lt;span style=&quot;font-size:12pt&quot;&gt;&lt;span style=&quot;text-justify:inter-ideograph&quot;&gt;&lt;span style=&quot;font-family:宋体&quot;&gt;&lt;strong&gt;&lt;i&gt;&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;&lt;span style=&quot;background-color:#27ae60;&quot;&gt;Tuesdays with Morrie&lt;/span&gt;&lt;/span&gt;&lt;/i&gt;&lt;/strong&gt;&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt; (&lt;i&gt;by Mitch Albom&lt;/i&gt;);&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt; 
   &lt;li style=&quot;margin-top:5px; margin-right:-42px; margin-bottom:5px; margin-left:36px; text-align:justify&quot;&gt;&lt;span style=&quot;font-size:12pt&quot;&gt;&lt;span style=&quot;text-justify:inter-ideograph&quot;&gt;&lt;span style=&quot;font-family:宋体&quot;&gt;&lt;strong&gt;&lt;i&gt;&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;&lt;span style=&quot;background-color:#27ae60;&quot;&gt;Merriam-Webster&rsquo;s Vocabulary Builder&lt;/span&gt;&lt;/span&gt;&lt;/i&gt;&lt;/strong&gt; &lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;(New Ed.) (&lt;span style=&quot;background:yellow&quot;&gt;&lt;span style=&quot;color:#00b050&quot;&gt;supplementary&lt;/span&gt;&lt;/span&gt;)&lt;/span&gt; （俗称&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;&ldquo;&lt;/span&gt;韦小绿&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;&rdquo;&lt;/span&gt;）&lt;span style=&quot;font-family:&amp;quot;Times New Roman&amp;quot;,serif&quot;&gt;.&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt; 
  &lt;/ol&gt;
